# Join orders.csv and products.csv on product_id, compute revenue per category
awk -F',' '
  # Load products into memory (skip header)
  NR==FNR {
    if (NR > 1)
      product[$1] = $3 "," $4   # product_id -> category,price
    next
  }
  # Process orders (skip header)
  FNR > 1 {
    pid = $2
    qty = $3
    split(product[pid], info, ",")
    cat   = info[1]
    price = info[2]
    revenue[cat] += qty * price
  }
  END {
    for (cat in revenue)
      print cat ": " revenue[cat]
